import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';

const Register = () => {
  const [role, setRole] = useState(''); // Initial state empty to force selection
  const [formData, setFormData] = useState({
    email: '',
    first_name: '',
    last_name: '',
    phone: '',
    address: '',
    password: '',
    confirm_password: '',
    qualification: '',
    hourly_rate: '',
    emergency_contact: '',
  });

  const [passwordCriteria, setPasswordCriteria] = useState({
    length: false,
    upper: false,
    lower: false,
    special: false
  });

  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { register, error, setError } = useAuth();
  const navigate = useNavigate();

  // Real-time password validation
  useEffect(() => {
    const pwd = formData.password;
    setPasswordCriteria({
      length: pwd.length >= 8,
      upper: /[A-Z]/.test(pwd),
      lower: /[a-z]/.test(pwd),
      special: /[!@#$%^&*(),.?":{}|<>]/.test(pwd)
    });
  }, [formData.password]);

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Max length validation for names
    if ((name === 'first_name' || name === 'last_name') && value.length > 75) {
      return;
    }

    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.email) newErrors.email = 'Email is required';
    if (!formData.first_name) newErrors.first_name = 'First name is required';
    if (!formData.last_name) newErrors.last_name = 'Last name is required';

    // Password strict validation
    if (!passwordCriteria.length || !passwordCriteria.upper ||
      !passwordCriteria.lower || !passwordCriteria.special) {
      newErrors.password = 'Please meet all password requirements.';
    }

    if (!formData.confirm_password) newErrors.confirm_password = 'Please confirm password';
    if (formData.password !== formData.confirm_password) {
      newErrors.confirm_password = 'Passwords do not match';
    }

    // Role-specific validations
    if (role === 'COACH') {
      if (!formData.qualification) newErrors.qualification = 'Qualification is required';
      if (!formData.hourly_rate || parseFloat(formData.hourly_rate) <= 0) {
        newErrors.hourly_rate = 'Valid hourly rate is required';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);

    if (!validateForm()) {
      return;
    }

    setIsSubmitting(true);

    const userData = {
      ...formData,
      role: role
    };

    if (role === "COACH") {
      userData.hourly_rate = Number(formData.hourly_rate);
    } else {
      delete userData.hourly_rate;
      delete userData.qualification;
    }
    // Remove unused fields
    if (role !== "PARENT") {
      delete userData.emergency_contact;
    }

    const result = await register(userData);

    if (result.success) {
      // Redirect based on role
      const userRole = result.user.role;
      switch (userRole) {
        case 'ADMIN': navigate('/admin/dashboard'); break;
        case 'CLERK': navigate('/clerk/dashboard'); break;
        case 'COACH': navigate('/coach/dashboard'); break;
        case 'PARENT': navigate('/parent/dashboard'); break;
        default: navigate('/');
      }
    }

    setIsSubmitting(false);
  };

  const renderPasswordChecklist = () => (
    <div className="card bg-light border-0 p-3 mb-3">
      <small className="fw-bold mb-2 d-block text-secondary">Password Requirements:</small>
      <div className="d-flex flex-wrap gap-3">
        <span className={passwordCriteria.length ? "text-success" : "text-muted"}>
          {passwordCriteria.length ? "✓" : "○"} At least 8 chars
        </span>
        <span className={passwordCriteria.upper ? "text-success" : "text-muted"}>
          {passwordCriteria.upper ? "✓" : "○"} 1 Uppercase
        </span>
        <span className={passwordCriteria.lower ? "text-success" : "text-muted"}>
          {passwordCriteria.lower ? "✓" : "○"} 1 Lowercase
        </span>
        <span className={passwordCriteria.special ? "text-success" : "text-muted"}>
          {passwordCriteria.special ? "✓" : "○"} 1 Special char
        </span>
      </div>
    </div>
  );

  // Initial Role Selection View
  if (!role) {
    return (
      <div className="auth-container">
        <div className="auth-card" style={{ maxWidth: '800px' }}>
          <div className="text-center mb-5">
            <h2 className="text-primary fw-bold">Join AAA Grand Masters</h2>
            <p className="lead text-muted">Select your account type to get started</p>
          </div>

          <div className="row g-4 justify-content-center">
            <div className="col-md-3">
              <div className="card h-100 text-center p-4 border-2 hover-shadow"
                style={{ cursor: 'pointer', borderColor: '#228B22' }}
                onClick={() => setRole('PARENT')}>
                <div className="display-4 mb-3">👨‍👩‍👧‍👦</div>
                <h4 className="text-primary">Parent</h4>
                <p className="text-muted small">For enrolling students and tracking progress.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card h-100 text-center p-4 border-2 hover-shadow"
                style={{ cursor: 'pointer', borderColor: '#228B22' }}
                onClick={() => setRole('COACH')}>
                <div className="display-4 mb-3">♟️</div>
                <h4 className="text-primary">Coach</h4>
                <p className="text-muted small">For masters teaching the next generation.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card h-100 text-center p-4 border-2 hover-shadow"
                style={{ cursor: 'pointer', borderColor: '#228B22' }}
                onClick={() => setRole('CLERK')}>
                <div className="display-4 mb-3">📝</div>
                <h4 className="text-primary">Clerk</h4>
                <p className="text-muted small">For administrative staff.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card h-100 text-center p-4 border-2 hover-shadow"
                style={{ cursor: 'pointer', borderColor: '#228B22' }}
                onClick={() => setRole('ADMIN')}>
                <div className="display-4 mb-3">⚙️</div>
                <h4 className="text-primary">Admin</h4>
                <p className="text-muted small">For system administrators.</p>
              </div>
            </div>
          </div>

          <div className="text-center mt-5">
            <p>Already have an account? <Link to="/login" className="text-primary fw-bold">Sign In</Link></p>
          </div>
        </div>
      </div>
    );
  }

  // Registration Form View
  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="text-center mb-4">
          <button className="btn btn-link text-decoration-none text-muted float-start" onClick={() => setRole('')}>
            ← Back
          </button>
          <h2 className="text-primary">Create {role.charAt(0) + role.slice(1).toLowerCase()} Account</h2>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {typeof error === 'object' ? JSON.stringify(error) : error}
            <button type="button" className="btn-close" onClick={() => setError(null)}></button>
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="row">
            <div className="col-md-6 mb-3">
              <label className="form-label">First Name</label>
              <input
                type="text"
                className={`form-control ${errors.first_name ? 'is-invalid' : ''}`}
                name="first_name"
                value={formData.first_name}
                onChange={handleChange}
                maxLength={75}
                required
              />
              {errors.first_name && <div className="invalid-feedback">{errors.first_name}</div>}
            </div>

            <div className="col-md-6 mb-3">
              <label className="form-label">Last Name</label>
              <input
                type="text"
                className={`form-control ${errors.last_name ? 'is-invalid' : ''}`}
                name="last_name"
                value={formData.last_name}
                onChange={handleChange}
                maxLength={75}
                required
              />
              {errors.last_name && <div className="invalid-feedback">{errors.last_name}</div>}
            </div>
          </div>

          <div className="mb-3">
            <label className="form-label">Email Address</label>
            <input
              type="email"
              className={`form-control ${errors.email ? 'is-invalid' : ''}`}
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
            />
            {errors.email && <div className="invalid-feedback">{errors.email}</div>}
          </div>

          <div className="mb-3">
            <label className="form-label">Phone Number</label>
            <input
              type="tel"
              className="form-control"
              name="phone"
              value={formData.phone}
              onChange={handleChange}
            />
          </div>

          <div className="mb-3">
            <label className="form-label">Address</label>
            <textarea
              className="form-control"
              name="address"
              value={formData.address}
              onChange={handleChange}
              rows="2"
            />
          </div>

          {/* Role Specific Fields */}
          {role === 'COACH' && (
            <>
              <div className="mb-3">
                <label className="form-label">Qualification *</label>
                <textarea
                  className={`form-control ${errors.qualification ? 'is-invalid' : ''}`}
                  name="qualification"
                  value={formData.qualification}
                  onChange={handleChange}
                  required
                />
                {errors.qualification && <div className="invalid-feedback">{errors.qualification}</div>}
              </div>
              <div className="mb-3">
                <label className="form-label">Hourly Rate (LKR) *</label>
                <input
                  type="number"
                  className={`form-control ${errors.hourly_rate ? 'is-invalid' : ''}`}
                  name="hourly_rate"
                  value={formData.hourly_rate}
                  onChange={handleChange}
                  min="0" step="0.01" required
                />
                {errors.hourly_rate && <div className="invalid-feedback">{errors.hourly_rate}</div>}
              </div>
            </>
          )}

          {role === 'PARENT' && (
            <div className="mb-3">
              <label className="form-label">Emergency Contact</label>
              <input
                type="tel"
                className="form-control"
                name="emergency_contact"
                value={formData.emergency_contact}
                onChange={handleChange}
              />
            </div>
          )}

          {/* Password Section */}
          <div className="mb-3">
            <label className="form-label">Password</label>
            <input
              type="password"
              className={`form-control ${errors.password ? 'is-invalid' : ''}`}
              name="password"
              value={formData.password}
              onChange={handleChange}
              required
            />
            {errors.password && <div className="invalid-feedback">{errors.password}</div>}
          </div>

          {/* Real-time Checklist */}
          {formData.password && renderPasswordChecklist()}

          <div className="mb-3">
            <label className="form-label">Confirm Password</label>
            <input
              type="password"
              className={`form-control ${errors.confirm_password ? 'is-invalid' : ''}`}
              name="confirm_password"
              value={formData.confirm_password}
              onChange={handleChange}
              required
            />
            {errors.confirm_password && <div className="invalid-feedback">{errors.confirm_password}</div>}
          </div>

          <button type="submit" className="btn btn-primary w-100 mb-3" disabled={isSubmitting}>
            {isSubmitting ? 'Creating Account...' : 'Register'}
          </button>

          <div className="text-center">
            <p className="mb-0">Already have an account? <Link to="/login" className="text-decoration-none">Login here</Link></p>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Register;
